mapper.select:
/* com.educare.edu.comn.mapper.EtcOrgCodeMapper.selectByPage */
	select a.*
	from t_etc_org_code a
	where 1=1

	order by a.full_nm
	LIMIT #{firstRecordIndex} ,#{recordCountPerPage}

mapper.insert:
/* com.educare.edu.comn.mapper.EtcOrgCodeMapper.insertByPk */
	INSERT INTO t_etc_org_code (org_cd, full_nm, low_nm)
    SELECT #{orgCd}, #{fullNm}, #{lowNm}
    WHERE NOT EXISTS (
        SELECT 1 FROM t_etc_org_code WHERE org_cd = #{orgCd}
    )
